// 取得當前輸入
const item = $input.item.json;

// 預設輸出物件
let data = {};

// --- Case 1️⃣：新建立成功（有 status / data 結構） ---
if (item.status && item.data) {
  data = item.data;

// --- Case 2️⃣：查詢現有資料（Ragic 回傳 { "67": {...} }） ---
} else {
  // 找出第一個 key（例如 "67"）
  const key = Object.keys(item)[0];
  const inner = item[key];

  // 如果該 key 的值確實是物件，代表是查詢資料
  if (inner && typeof inner === 'object') {
    data = inner;
  } else {
    throw new Error('❌ 無法辨識輸入格式，請檢查 Ragic 回傳內容');
  }
}

// === 統一回傳格式 ===
return data;

// 1. 定義資料來源
const oldData = $node["格式化_降解"].json; 
const newData = $('Loop Over Items').item.json; 

// 2. 初始化更新物件
let updatePayload = {};

/**
 * 輔助函數：比對差異
 * newValue: 來自 Loop 的新資料
 * oldFieldName: Ragic 舊資料的「中文標題」
 */
const addToPayload = (fieldId, newValue, oldFieldName) => {
    const newVal = (newValue || "").toString().trim();
    const oldVal = (oldData[oldFieldName] || "").toString().trim(); // 使用正確的中文名稱抓取舊值

    if (newVal !== "" && newVal !== oldVal) {
        updatePayload[fieldId] = newVal;
    }
};

/**
 * 輔助函數：補位判斷 (舊值為空才填入)
 */
const fillIfEmpty = (fieldId, newValue, oldFieldName) => {
    const oldVal = (oldData[oldFieldName] || "").toString().trim();
    if (oldVal === "") {
        if (newValue) updatePayload[fieldId] = newValue;
    }
};

// --- 開始比對邏輯 (嚴格對照你提供的表單) ---

// [房客基本資訊]
addToPayload("1020354", newData['承租方'], '房客姓名1');
fillIfEmpty("1020355", newData['性別'], '性別');
addToPayload("1020360", newData['email'], 'email');
addToPayload("1020358", newData['房客2'], '房客姓名2');

// [地址與證件] - 修正了你剛才提到的 1020364 抓取錯誤
addToPayload("1020364", newData['通訊地址'], '緊急聯絡人地址'); 
addToPayload("1020373", newData['戶籍地址'], '戶籍地址');
addToPayload("1020368", newData['身分證字號'], '身分證字號');

// [第一組緊急聯絡人] (補位邏輯：舊的姓名1為空才補)
if (!(oldData['緊急連絡人姓名1']) || oldData['緊急連絡人姓名1'].trim() === "") {
    if (newData['緊急聯絡人']) {
        updatePayload["1020361"] = newData['緊急聯絡人'];
        updatePayload["1020362"] = newData['緊急電話'];
        updatePayload["1020363"] = newData['緊急聯絡人關係'];
    }
}

// [第二組緊急聯絡人] (溢位補位邏輯)
// 條件：新聯絡人不同於舊姓名1 且 舊姓名2為空
if (newData['緊急聯絡人'] !== oldData['緊急連絡人姓名1'] && (!oldData['緊急連絡人姓名2'] || oldData['緊急連絡人姓名2'].trim() === "")) {
    updatePayload["1020365"] = newData['緊急聯絡人'];
    updatePayload["1020366"] = newData['緊急電話'];
    updatePayload["1020367"] = newData['緊急聯絡人關係'];
}

// [副電話 1020357 補位邏輯]
// 優先看房客2電話，沒有則看是否要補入主承租人電話
if (newData['房客2電話']) {
    addToPayload("1020357", newData['房客2電話'], '連絡電話2');
} else if (newData['主承租人電話'] !== oldData['連絡電話1'] && (!oldData['緊急連絡人姓名2'])) {
    updatePayload["1020357"] = newData['主承租人電話'];
}

// [系統更新日期]
updatePayload["1020576"] = new Date().toISOString(); 

// 3. 輸出結果
return {
    ragicId: oldData._ragicId,
    hasChanges: Object.keys(updatePayload).length > 1, // 扣除時間戳記後是否有變動
    updatePayload: updatePayload
};

