// === 1. 格式化邏輯 (原：格式化_降解) ===
const rawInput = $input.item.json;
let oldData = {};

if (rawInput.status && rawInput.data) {
    oldData = rawInput.data;
} else {
    const key = Object.keys(rawInput)[0];
    const inner = rawInput[key];
    if (inner && typeof inner === 'object') {
        oldData = inner;
    } else {
        throw new Error('❌ 無法辨識 Ragic 輸入格式');
    }
}

// 💡 【核心修改：智慧提取原合約編號】
// 1. 取得「確認合約版本」節點傳出的當前合約編號 (例如 A02501)
const currentContractInfo = Object.values($('確認合約版本').first().json)[0];
const targetContractId = currentContractInfo ? currentContractInfo["合約編號"] : "";

// 2. 取得子表格陣列
const subtable = oldData['_subtable_1007371'] || {};
const subtableEntries = Object.values(subtable); 

let prevContractId = "";

if (targetContractId && subtableEntries.length > 0) {
    // 3. 在子表格中找到當前合約的索引位置
    const currentIndex = subtableEntries.findIndex(entry => entry['合約編號'] === targetContractId);

    // 4. 如果找到了且不是第一筆，則取前一筆的編號
    if (currentIndex > 0) {
        prevContractId = subtableEntries[currentIndex - 1]['合約編號'] || "";
    }
}

// === 2. 取得新資料來源 ===
const newData = $('Loop Over Items').item.json; 

// === 3. 初始化更新物件 ===
let updatePayload = {};

// 輔助函數：比對差異
const addToPayload = (fieldId, newValue, oldFieldName) => {
    const newVal = (newValue || "").toString().trim();
    const oldVal = (oldData[oldFieldName] || "").toString().trim();
    if (newVal !== "" && newVal !== oldVal) {
        updatePayload[fieldId] = newVal;
    }
};

// 輔助函數：補位判斷
const fillIfEmpty = (fieldId, newValue, oldFieldName) => {
    const oldVal = (oldData[oldFieldName] || "").toString().trim();
    if (oldVal === "") {
        if (newValue) updatePayload[fieldId] = (newValue || "").toString().trim();
    }
};

// === 4. 開始執行比對 ===

// [房客基本資訊]
addToPayload("1007373", newData['承租方'], '房客姓名1');
fillIfEmpty("1007376", newData['性別'], '性別');
addToPayload("1007542", newData['email'], 'email');
addToPayload("1008188", newData['房客2'], '房客姓名2');

// [地址與證件]
addToPayload("1013892", newData['通訊地址'], '緊急聯絡人地址');
addToPayload("1007378", newData['戶籍地址'], '戶籍地址');
addToPayload("1007374", newData['身分證字號'], '身分證字號');

// [第一組緊急聯絡人]
addToPayload("1007379", newData['緊急聯絡人'], '緊急連絡人姓名1');
addToPayload("1007381", newData['緊急電話'], '緊急連絡人電話1');
addToPayload("1007380", newData['緊急聯絡人關係'], '緊急聯絡人關係1');

// [第二組緊急聯絡人]
if (newData['緊急聯絡人'] !== oldData['緊急連絡人姓名1'] && (!oldData['緊急連絡人姓名2'] || oldData['緊急連絡人姓名2'].toString().trim() === "")) {
    updatePayload["1008191"] = newData['緊急聯絡人'];      
    updatePayload["1008192"] = newData['緊急電話'];        
    updatePayload["1008193"] = newData['緊急聯絡人關係'];  
}

// [副電話 1008189 補位]
if (newData['房客2電話']) {
    addToPayload("1008189", newData['房客2電話'], '連絡電話2');
} else if (newData['主承租人電話'] !== oldData['連絡電話1'] && (!oldData['緊急連絡人姓名2'])) {
    updatePayload["1008189"] = newData['主承租人電話'];
}

// [系統更新日期]
const now = new Date();
const twTime = new Date(now.getTime() + 8 * 60 * 60 * 1000)
    .toISOString()
    .replace('T', ' ')
    .substring(0, 19);

updatePayload["1021727"] = twTime;

// === 5. 輸出結果 ===
return {
    ragicId: oldData._ragicId,
    targetContractId: targetContractId, // 偵錯用：當前合約
    prevContractId: prevContractId,     // 智慧提取出的前一個合約
    hasChanges: Object.keys(updatePayload).length > 1, 
    updatePayload: updatePayload
};

// === 1. 解析 Ragic 原始輸入 (oldData) ===
const item = $input.item.json || {}; // 防止 $input 為空
let oldData = {};
let isNewlyCreated = false;

// 💡 優化判斷邏輯：確保 item 存在且結構正確
if (item.status === "SUCCESS" && item.data) {
    // [新增成功路徑]
    oldData = item.data;
    isNewlyCreated = true;
} else {
    // [現有資料路徑] 取得第一個 Key 內部的物件
    const keys = Object.keys(item);
    if (keys.length > 0) {
        // 排除 n8n 有時會帶入的屬性，確保抓到的是資料物件
        const dataKey = keys.find(k => typeof item[k] === 'object' && item[k] !== null);
        oldData = dataKey ? item[dataKey] : item[keys[0]];
    }
}

// 💡 確保安全取得 ragicId
const ragicId = oldData ? oldData._ragicId : null;

// === 2. 取得新資料來源 (newData) 與 跨節點變數 ===
// 使用 optional chaining (?.) 防止節點未執行或資料缺失導致崩潰
const newData = $('Loop Over Items').first()?.json || {}; 
const prevContractIdFromNode = $('差異比較_租客').first()?.json?.prevContractId || "";

// === 3. 初始化輸出變數 ===
let updatePayload = {};

/**
 * 輔助函數：標準化值 (處理日期格式或多選欄位)
 */
const normalize = (val) => {
    if (val === null || val === undefined) return "";
    if (Array.isArray(val)) return val.join(",").trim(); 
    return val.toString().trim().replace(/\//g, '-'); 
};

// === 4. 執行比對邏輯 (僅針對「已存在」的資料進行) ===
if (!isNewlyCreated && oldData) {

    // --- 原合約編號 (1014734) ---
    if (prevContractIdFromNode && prevContractIdFromNode.toString().trim() !== "") {
        updatePayload["1014734"] = prevContractIdFromNode.toString().trim();
    }

    // --- 租客手機1 (1007361) 強制比對 ---
    const masterPhone = normalize(oldData['在此登打電話(必填)']);
    const currentPhone1 = normalize(oldData['租客手機1']);

    if (masterPhone !== "" && currentPhone1 !== masterPhone) {
        updatePayload["1007361"] = masterPhone;
    }

    // --- 規則 1: 不同就更新 ---
    const newPayType = normalize(newData['繳費方式']);
    const oldPayType = normalize(oldData['繳費方式']);
    if (newPayType !== "" && newPayType !== oldPayType) {
        updatePayload["1007366"] = newData['繳費方式'];
    }

    const newEndDate = normalize(newData['到期日']);
    const oldEndDate = normalize(oldData['合約到期日']);
    if (newEndDate !== "" && newEndDate !== oldEndDate) {
        updatePayload["1007368"] = newData['到期日'];
    }

    // --- 規則 2: 舊的若為空才填 ---
    const oldRoom = normalize(oldData['房間編號(可多選)']);
    if (oldRoom === "" && newData['第__室']) {
        updatePayload["1007552"] = newData['第__室'].toString().trim();
    }

    const oldCaseId = normalize(oldData['案場編號(一定要有數字)']);
    if (oldCaseId === "" && newData['案場編號']) {
        updatePayload["1008219"] = newData['案場編號'].toString().trim();
    }
}

// === 5. 系統欄位與最終輸出 ===
const now = new Date();
const twTime = new Date(now.getTime() + 8 * 60 * 60 * 1000)
    .toISOString()
    .replace('T', ' ')
    .substring(0, 19);

updatePayload["1019665"] = twTime;

// 判斷是否有「實質內容」更動
const hasRealChanges = Object.keys(updatePayload).length > 1;

return {
    ragicId: ragicId,
    isNewlyCreated: isNewlyCreated, 
    hasChanges: isNewlyCreated ? false : hasRealChanges, 
    updatePayload: updatePayload
};

// 讀取目前的重試次數，如果沒有就從 0 開始
let currentCount = $('Wait').context.retryCount || 0;

// 次數 +1
currentCount += 1;

// 把次數存回環境變數裡，讓下一圈可以讀取
$('Wait').context.retryCount = currentCount;

return {
  json: {
    ...$input.item.json,
    retryCount: currentCount
  }
};
